;a:9:{s:4:\"slug\";s:42:\"orders-list-empty-body-table-rate-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:19:\"table-rate-shipping\";s:4:\"icon\";s:101:\"https://woocommerce.com/wp-content/uploads/2012/07/Table_Rate_Shipping_icon-marketplace-160x160-2.png\";s:5:\"title\";s:19:\"Table Rate Shipping\";s:4:\"copy\";s:123:\"Advanced, flexible shipping. Define multiple shipping rates based on location, price, weight, shipping class or item count.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:53:\"https://woocommerce.com/products/table-rate-shipping/\";s:9:\"is_pinned\";b:1;}i:8;a:9:{s:4:\"slug\";s:56:\"orders-list-empty-body-conditional-shipping-and-payments\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:33:\"conditional-shipping-and-payments\";s:4:\"icon\";s:111:\"https://woocommerce.com/wp-content/uploads/2015/03/Conditional_Shipping_Payments_icon-marketplace-160x160-1.png\";s:5:\"title\";s:33:\"Conditional Shipping and Payments\";s:4:\"copy\";s:91:\"Use conditional logic to restrict the shipping and payment options available on your store.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:67:\"https://woocommerce.com/products/conditional-shipping-and-payments/\";s:9:\"is_pinned\";b:1;}i:9;a:9:{s:4:\"slug\";s:40:\"orders-list-empty-body-shipment-tracking\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:17:\"shipment-tracking\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/05/Shipment_Tracking_icon-marketplace-160x160-2.png\";s:5:\"title\";s:17:\"Shipment Tracking\";s:4:\"copy\";s:49:\"Add shipment tracking information to your orders.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:51:\"https://woocommerce.com/products/shipment-tracking/\";s:9:\"is_pinned\";b:1;}i:10;a:8:{s:4:\"slug\";s:46:\"orders-list-empty-body-shipstation-integration\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:23:\"shipstation-integration\";s:4:\"icon\";s:73:\"https://woocommerce.com/wp-content/uploads/2012/08/ShipStation-Icon-1.png\";s:5:\"title\";s:11:\"ShipStation\";s:4:\"copy\";s:113:\"Ship your WooCommerce orders with confidence, save on top carriers, and automate your processes with ShipStation.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/shipstation-integration/\";}i:11;a:8:{s:4:\"slug\";s:31:\"orders-list-empty-body-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:8:\"shipping\";s:4:\"icon\";s:76:\"https://woocommerce.com/wp-content/uploads/2017/06/icon-shipping_160x160.png\";s:5:\"title\";s:20:\"WooCommerce Shipping\";s:4:\"copy\";s:174:\"Print USPS, UPS, DHL, and FedEx labels right from your WooCommerce dashboard and instantly save on shipping. WooCommerce Shipping is free to use and saves you time and money.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:42:\"https://woocommerce.com/products/shipping/\";}i:12;a:8:{s:4:\"slug\";s:46:\"orders-list-empty-body-easyship-shipping-rates\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:23:\"easyship-shipping-rates\";s:4:\"icon\";s:95:\"https://woocommerce.com/wp-content/uploads/2023/09/Ecwid-Easyship-App-Assets_Logo-instasize.png\";s:5:\"title\";s:8:\"Easyship\";s:4:\"copy\";s:66:\"Simplify shipping with Easyship, the all-in-one shipping platform.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/easyship-shipping-rates/\";}i:13;a:8:{s:4:\"slug\";s:34:\"orders-list-empty-body-scanventory\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:11:\"scanventory\";s:4:\"icon\";s:68:\"https://woocommerce.com/wp-content/uploads/2018/06/estudios-icon.jpg\";s:5:\"title\";s:51:\"Scanventory – Inventory Manager & Label Generator\";s:4:\"copy\";s:99:\"Synchronize your warehouse inventory with your WooCommerce store products using your mobile device.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:45:\"https://woocommerce.com/products/scanventory/\";}i:14;a:8:{s:4:\"slug\";s:72:\"orders-list-empty-body-ph-order-and-shipment-tracking-with-notifications\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:49:\"ph-order-and-shipment-tracking-with-notifications\";s:4:\"icon\";s:76:\"https://woocommerce.com/wp-content/uploads/2026/04/shipment-tracking-160.jpg\";s:5:\"title\";s:47:\"PH Order & Shipment Tracking with Notifications\";s:4:\"copy\";s:187:\"Enhance your WooCommerce store with shipment tracking that integrates with 80+ major carriers, sends automatic tracking notifications with live tracking updates directly to the customers.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:83:\"https://woocommerce.com/products/ph-order-and-shipment-tracking-with-notifications/\";}i:15;a:8:{s:4:\"slug\";s:64:\"orders-list-empty-body-delivery-pickup-scheduler-for-woocommerce\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:41:\"delivery-pickup-scheduler-for-woocommerce\";s:4:\"icon\";s:81:\"https://woocommerce.com/wp-content/uploads/2021/02/delivery-slot-icon-new-160.png\";s:5:\"title\";s:29:\"Delivery and Pickup Scheduler\";s:4:\"copy\";s:139:\"Allow users to select a date & time of delivery/pickup for orders & products. You can also display an estimated date for orders & products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:75:\"https://woocommerce.com/products/delivery-pickup-scheduler-for-woocommerce/\";}i:16;a:8:{s:4:\"slug\";s:45:\"orders-list-empty-body-flat-rate-box-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:22:\"flat-rate-box-shipping\";s:4:\"icon\";s:104:\"https://woocommerce.com/wp-content/uploads/2013/04/Flat_Rate_Box_Shipping_icon-marketplace-160x160-1.png\";s:5:\"title\";s:22:\"Flat Rate Box Shipping\";s:4:\"copy\";s:60:\"Pack items into boxes with pre-defined costs per destination\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:56:\"https://woocommerce.com/products/flat-rate-box-shipping/\";}i:17;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-add-ons\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-add-ons\";s:4:\"icon\";s:96:\"https://woocommerce.com/wp-content/uploads/2013/05/Product_Addons_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Add-Ons\";s:4:\"copy\";s:94:\"Offer add-ons like gift wrapping, special messages or other special options for your products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-add-ons/\";s:9:\"is_pinned\";b:1;}i:18;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-bundles\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-bundles\";s:4:\"icon\";s:97:\"https://woocommerce.com/wp-content/uploads/2012/07/Product_Bundles_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Bundles\";s:4:\"copy\";s:84:\"Offer personalized product bundles, bulk discount packages, and assembled products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-bundles/\";s:9:\"is_pinned\";b:1;}i:19;a:9:{s:4:\"slug\";s:47:\"product-edit-meta-tab-body-woocommerce-bookings\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:20:\"woocommerce-bookings\";s:4:\"icon\";s:90:\"https://woocommerce.com/wp-content/uploads/2014/05/Bookings_icon-marketplace-160x160-1.png\";s:5:\"title\";s:20:\"WooCommerce Bookings\";s:4:\"copy\";s:101:\"Allow customers to book appointments, make reservations, or rent equipment without leaving your site.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:54:\"https://woocommerce.com/products/woocommerce-bookings/\";s:9:\"is_pinned\";b:1;}i:20;a:9:{s:4:\"slug\";s:52:\"product-edit-meta-tab-body-woocommerce-subscriptions\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:25:\"woocommerce-subscriptions\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/09/Woo_Subscriptions_icon-marketplace-160x160-2.png\";s:5:\"title\";s:25:\"WooCommerce Subscriptions\";s:4:\"copy\";s:98:\"Let customers subscribe to your products or services and pay on a weekly, monthly or annual basis.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:59:\"https://woocommerce.com/products/woocommerce-subscriptions/\";s:9:\"is_pinned\";b:1;}i:21;a:9:{s:4:\"slug\";s:45:\"product-edit-meta-tab-body-composite-products\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:18:\"composite-products\";s:4:\"icon\";s:100:\"https://woocommerce.com/wp-content/uploads/2013/06/Composite_Products_icon-marketplace-160x160-1.png\";s:5:\"title\";s:18:\"Composite Products\";s:4:\"copy\";s:85:\"Create product kit builders and custom product configurators using existing products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:52:\"https://woocommerce.com/products/composite-products/\";s:9:\"is_pinned\";b:1;}i:22;a:8:{s:4:\"slug\";s:58:\"product-edit-meta-tab-body-bulk-order-form-for-woocommerce\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:31:\"bulk-order-form-for-woocommerce\";s:4:\"icon\";s:88:\"https://woocommerce.com/wp-content/uploads/2020/04/Bulk-Order-Form-For-WooCommerce-3.png\";s:5:\"title\";s:32:\"Bulk Order – B2B Product Table\";s:4:\"copy\";s:115:\"Revolutionize product tables through Bulk Order Form for WooCommerce. Add sorting, search, pagination, and filters.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:65:\"https://woocommerce.com/products/bulk-order-form-for-woocommerce/\";}i:23;a:8:{s:4:\"slug\";s:52:\"product-edit-meta-tab-body-buy-again-for-woocommerce\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:25:\"buy-again-for-woocommerce\";s:4:\"icon\";s:77:\"https://woocommerce.com/wp-content/uploads/2019/12/buy-again-icon-new-160.png\";s:5:\"title\";s:9:\"Buy Again\";s:4:\"copy\";s:130:\"Using Buy Again for WooCommerce your customers can quickly re-purchase the products which they had purchased earlier in your site.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:59:\"https://woocommerce.com/products/buy-again-for-woocommerce/\";}i:24;a:8:{s:4:\"slug\";s:50:\"product-edit-meta-tab-body-woocommerce-api-manager\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:23:\"woocommerce-api-manager\";s:4:\"icon\";s:77:\"https://woocommerce.com/wp-content/uploads/2013/10/Kestrel-product-logo-1.png\";s:5:\"title\";s:19:\"Kestrel API Manager\";s:4:\"copy\";s:136:\"Grow your recurring revenue with flexible licensing, subscription billing, and software delivery, all powered by your WooCommerce store.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/woocommerce-api-manager/\";}i:25;a:8:{s:4:\"slug\";s:48:\"product-edit-meta-tab-body-recommendation-engine\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:21:\"recommendation-engine\";s:4:\"icon\";s:95:\"https://woocommerce.com/wp-content/uploads/2013/06/Recommendation_Engine_Marketplace_Icon-1.png\";s:5:\"title\";s:21:\"Recommendation Engine\";s:4:\"copy\";s:465:\"Boost your store\'s sales with intelligent product recommendations that analyze customer behavior in real-time. This powerful plugin automatically suggests relevant products based on viewing and purchasing patterns, increasing average order value and improving conversion rates. With blazingly fast performance and secure on-site processing, you can deliver personalized shopping experiences that keep customers coming back for more. Easy to set up, powerful to use.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:55:\"https://woocommerce.com/products/recommendation-engine/\";}i:26;a:8:{s:4:\"slug\";s:41:\"product-edit-meta-tab-body-multi-currency\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:14:\"multi-currency\";s:4:\"icon\";s:76:\"https://woocommerce.com/wp-content/uploads/2018/06/tiv-multicurrency-160.png\";s:5:\"title\";s:18:\"TIV Multi-Currency\";s:4:\"copy\";s:212:\"Multi-currency support for WooCommerce. The exchange rate can be set up manually or automatically. The plugin can automatically get customer\'s geolocation and display the price in the customer country\'s currency.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:48:\"https://woocommerce.com/products/multi-currency/\";}}s:7:\"updated\";i:1780044217;}', 'off'),
